  ('lib.lead.lead_with_no_follow_up', 'lead', 'agent', 'follow_up_required', 'לידים: פער בטיפול בהליד (וריאנט 5)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הליד מציג פער (ליד עם ללא מעקב) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'לידים: פער בטיפול בהליד (וריאנט 5)', 'השלם את החסר בהליד (ליד עם ללא מעקב) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהליד (ליד עם ללא מעקב) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהליד. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־9,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והליד חוזר למסלול טיפול פעיל.', 'לידים: ליד עם ללא מעקב. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והליד חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (לידים/ליד עם ללא מעקב) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.lead.lead_with_missed_follow_up', 'lead', 'agent', 'deal_risk', 'לידים: סיכון פעיל בהליד', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'זוהה סיכון פעיל שעלול לפגוע בהתקדמות או בהכנסה.', 'הליד נמצא בסיכון (ליד עם הוחמץ מעקב). מצב זה עלול לעצור התקדמות ולפגוע בהכנסה צפויה אם לא יטופל. מומלץ לזהות את שורש הסיכון, לפעול להפחתתו ולעדכן את בעלי העניין.', 'לידים: סיכון פעיל בהליד', 'טפל בשורש הסיכון בהליד (ליד עם הוחמץ מעקב) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'טפל בשורש הסיכון בהליד (ליד עם הוחמץ מעקב) בפעולה ממוקדת, ועדכן על הצעד שננקט.', 'הליד בסיכון שעלול לעלות בהכנסה. שקול התערבות ניהולית או ליווי מיידי.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־9,000 ₪ בעסקה ממוצעת מסוג זה.', 'סיכון לא מטופל מתגבר ועלול להפוך לאובדן עסקה.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', 'לידים: ליד עם הוחמץ מעקב. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הסיכון מטופל וההתקדמות חוזרת למסלול בטוח.', null, null, null, 'אוטומציה (לידים/ליד עם הוחמץ מעקב) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.lead.lead_viewed_portal', 'lead', 'agent', 'customer_risk', 'לידים: הליד גילה מעורבות פעילה', 'הליד גילה מעורבות פעילה — הרגע הנכון להמשך יזום.', 'הליד גילה מעורבות פעילה — הרגע הנכון להמשך יזום.', 'הליד ביצע פעולת מעורבות (ליד נצפה פורטל). מעורבות יזומה היא אות חם: הלקוח עוסק באופן פעיל. מומלץ לנצל את המומנטום בפנייה רלוונטית שממשיכה בדיוק מהנקודה שבה הוא התעניין.', 'לידים: הליד גילה מעורבות פעילה', 'הליד מעורב עכשיו — פנה בהקשר למה שצפה/לחץ, והצע צעד המשך טבעי (פרטים, סיור או שיחה).', 'הליד מעורב עכשיו — פנה בהקשר למה שצפה/לחץ, והצע צעד המשך טבעי (פרטים, סיור או שיחה).', 'זוהתה מעורבות פעילה של הליד. ודא מענה מהיר כדי להמיר עניין לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'מענה תוך זמן קצר ממעורבות מגדיל מהותית את סיכויי ההמרה.', 'המעורבות מנוצלת ומומרת לצעד התקדמות מוחשי.', 'לידים: ליד נצפה פורטל. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'המעורבות מנוצלת ומומרת לצעד התקדמות מוחשי.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא ליד נצפה פורטל. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא ליד נצפה פורטל. הסוכן/ת שלך זמין/ה להמשך.', 'תודה על פנייתך. סוכן/ת מטעמנו ייצור/תיצור קשר בהקדם להמשך אישי בנושא ליד נצפה פורטל.', 'אוטומציה (לידים/ליד נצפה פורטל) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.lead.lead_clicked_whatsapp', 'lead', 'agent', 'customer_risk', 'לידים: הליד גילה מעורבות פעילה (וריאנט 2)', 'הליד גילה מעורבות פעילה — הרגע הנכון להמשך יזום.', 'הליד גילה מעורבות פעילה — הרגע הנכון להמשך יזום.', 'הליד ביצע פעולת מעורבות (ליד נלחץ וואטסאפ). מעורבות יזומה היא אות חם: הלקוח עוסק באופן פעיל. מומלץ לנצל את המומנטום בפנייה רלוונטית שממשיכה בדיוק מהנקודה שבה הוא התעניין.', 'לידים: הליד גילה מעורבות פעילה (וריאנט 2)', 'הליד מעורב עכשיו — פנה בהקשר למה שצפה/לחץ, והצע צעד המשך טבעי (פרטים, סיור או שיחה).', 'הליד מעורב עכשיו — פנה בהקשר למה שצפה/לחץ, והצע צעד המשך טבעי (פרטים, סיור או שיחה).', 'זוהתה מעורבות פעילה של הליד. ודא מענה מהיר כדי להמיר עניין לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'מענה תוך זמן קצר ממעורבות מגדיל מהותית את סיכויי ההמרה.', 'המעורבות מנוצלת ומומרת לצעד התקדמות מוחשי.', 'לידים: ליד נלחץ וואטסאפ. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'המעורבות מנוצלת ומומרת לצעד התקדמות מוחשי.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא ליד נלחץ וואטסאפ. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא ליד נלחץ וואטסאפ. הסוכן/ת שלך זמין/ה להמשך.', 'תודה על פנייתך. סוכן/ת מטעמנו ייצור/תיצור קשר בהקדם להמשך אישי בנושא ליד נלחץ וואטסאפ.', 'אוטומציה (לידים/ליד נלחץ וואטסאפ) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.lead.lead_submitted_same_property_twice', 'lead', 'agent', 'high_priority', 'לידים: ליד הוגש זהה נכס פעמיים', 'זוהה אירוע בלידים שמצדיק פעולה יזומה.', 'זוהה אירוע בלידים שמצדיק פעולה יזומה.', 'זוהה אירוע בלידים (ליד הוגש זהה נכס פעמיים) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'לידים: ליד הוגש זהה נכס פעמיים', 'בחן את ההקשר של ליד הוגש זהה נכס פעמיים בהליד, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של ליד הוגש זהה נכס פעמיים בהליד, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בלידים (ליד הוגש זהה נכס פעמיים) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'לידים: ליד הוגש זהה נכס פעמיים. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (לידים/ליד הוגש זהה נכס פעמיים) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.lead.lead_connected_to_hot_territory', 'lead', 'agent', 'high_priority', 'לידים: הליד בכוונה גבוהה — חלון הזדמנות (וריאנט 4)', 'הליד מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הליד מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הליד מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (ליד מחובר חם טריטוריה). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'לידים: הליד בכוונה גבוהה — חלון הזדמנות (וריאנט 4)', 'הליד חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הליד חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הליד בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'הליד מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'לידים: ליד מחובר חם טריטוריה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הליד מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא ליד מחובר חם טריטוריה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, 'תודה על פנייתך. סוכן/ת מטעמנו ייצור/תיצור קשר בהקדם להמשך אישי בנושא ליד מחובר חם טריטוריה.', 'אוטומציה (לידים/ליד מחובר חם טריטוריה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.')
