  urgency_reason_he=excluded.urgency_reason_he, expected_outcome_he=excluded.expected_outcome_he, decision_brain_summary_he=excluded.decision_brain_summary_he,
  success_definition_he=excluded.success_definition_he, client_draft_message_he=excluded.client_draft_message_he, portal_message_he=excluded.portal_message_he,
