  ('lib.lead.lead_requires_manager_review', 'lead', 'agent', 'manager_review', 'לידים: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'הליד הגיע לרף שמצדיק מעורבות ניהולית (ליד דורש מנהל בדיקה). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'לידים: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים להליד והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים להליד והעבר לאישור/ליווי ניהולי לפני פעולה.', 'הליד דורש החלטה ניהולית (ליד דורש מנהל בדיקה). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־9,000 ₪ בעסקה ממוצעת.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'לידים: ליד דורש מנהל בדיקה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (לידים/ליד דורש מנהל בדיקה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.buyer.buyer_created', 'buyer', 'agent', 'quick_win', 'קונים: הקונה חדש נכנס למערכת', 'הקונה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הקונה נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הקונה נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'קונים: הקונה חדש נכנס למערכת', 'הקונה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הקונה חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הקונה חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־14,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הקונה מטופל, משויך ומקודם לצעד הבא במסלול.', 'קונים: קונה נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקונה מטופל, משויך ומקודם לצעד הבא במסלול.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא קונה נוצר. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (קונים/קונה נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.buyer.buyer_twin_missing', 'buyer', 'agent', 'follow_up_required', 'קונים: פער בטיפול בהקונה', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הקונה מציג פער (קונה תאום חסר) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'קונים: פער בטיפול בהקונה', 'השלם את החסר בהקונה (קונה תאום חסר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהקונה (קונה תאום חסר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהקונה. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־14,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והקונה חוזר למסלול טיפול פעיל.', 'קונים: קונה תאום חסר. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והקונה חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (קונים/קונה תאום חסר) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
