values
  ('lib.buyer.buyer_has_new_matching_properties', 'buyer', 'agent', 'revenue_opportunity', 'קונים: הזדמנות שכדאי לממש', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות עסקית מוחשית שכדאי לממש.', 'זוהתה הזדמנות בקונים (קונה בעל חדש תואמים נכסים). הזדמנויות מסוג זה נסגרות מהר על ידי מי שפועל ראשון. מומלץ לבחון, לתעדף ולהתחיל בפעולה מבוקרת למימוש הערך.', 'קונים: הזדמנות שכדאי לממש', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'קיימת הזדמנות מוחשית — בדוק את ההקשר, ופעל לקידומה בצעד ממוקד אחד שמייצר התקדמות.', 'הזדמנות בקונים ממתינה למימוש. ודא בעלות ברורה ולוח זמנים לפעולה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־14,000 ₪ בעסקה ממוצעת.', 'הזדמנויות לא ממומשות מתכלות במהירות וזולגות למתחרים.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', 'קונים: קונה בעל חדש תואמים נכסים. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההזדמנות נבדקת ומקודמת למימוש ערך.', null, null, null, 'אוטומציה (קונים/קונה בעל חדש תואמים נכסים) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.buyer.buyer_should_receive_recommendation_package', 'buyer', 'agent', 'quick_win', 'קונים: הקונה בשל לקבלת ערך ממוקד', 'הגיע הזמן לספק להקונה ערך ממוקד ומותאם.', 'הגיע הזמן לספק להקונה ערך ממוקד ומותאם.', 'הקונה בשל לקבלת תוצר ערך מותאם (קונה קבלת המלצה חבילה). אספקת תובנה או חבילה רלוונטית בזמן הנכון מחזקת אמון ומקדמת החלטה. מומלץ להכין את התוצר ולהציגו באופן אישי.', 'קונים: הקונה בשל לקבלת ערך ממוקד', 'הכן להקונה את התוצר המתאים (קונה קבלת המלצה חבילה) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'הכן להקונה את התוצר המתאים (קונה קבלת המלצה חבילה) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'הקונה ראוי לאספקת ערך ממוקד. ודא שהתוצר הוכן ונמסר באיכות גבוהה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־14,000 ₪ בעסקה ממוצעת.', 'אספקת ערך בעיתוי הנכון מחזקת אמון ומקצרת את מסלול ההחלטה.', 'הקונה מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'קונים: קונה קבלת המלצה חבילה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקונה מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא קונה קבלת המלצה חבילה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא קונה קבלת המלצה חבילה. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (קונים/קונה קבלת המלצה חבילה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.buyer.buyer_should_receive_transaction_package', 'buyer', 'agent', 'quick_win', 'קונים: הקונה בשל לקבלת ערך ממוקד (וריאנט 2)', 'הגיע הזמן לספק להקונה ערך ממוקד ומותאם.', 'הגיע הזמן לספק להקונה ערך ממוקד ומותאם.', 'הקונה בשל לקבלת תוצר ערך מותאם (קונה קבלת עסקה חבילה). אספקת תובנה או חבילה רלוונטית בזמן הנכון מחזקת אמון ומקדמת החלטה. מומלץ להכין את התוצר ולהציגו באופן אישי.', 'קונים: הקונה בשל לקבלת ערך ממוקד (וריאנט 2)', 'הכן להקונה את התוצר המתאים (קונה קבלת עסקה חבילה) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'הכן להקונה את התוצר המתאים (קונה קבלת עסקה חבילה) והצג אותו בפנייה אישית שמסבירה את הערך עבורו.', 'הקונה ראוי לאספקת ערך ממוקד. ודא שהתוצר הוכן ונמסר באיכות גבוהה.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־14,000 ₪ בעסקה ממוצעת.', 'אספקת ערך בעיתוי הנכון מחזקת אמון ומקצרת את מסלול ההחלטה.', 'הקונה מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'קונים: קונה קבלת עסקה חבילה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקונה מקבל ערך מותאם שמקדם אותו לשלב הבא.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא קונה קבלת עסקה חבילה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', 'עדכון אישי בפורטל: הכנו עבורך מידע ממוקד בנושא קונה קבלת עסקה חבילה. הסוכן/ת שלך זמין/ה להמשך.', null, 'אוטומציה (קונים/קונה קבלת עסקה חבילה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.buyer.buyer_budget_below_target_area', 'buyer', 'agent', 'high_priority', 'קונים: קונה תקציב מתחת יעד אזור', 'זוהה אירוע בקונים שמצדיק פעולה יזומה.', 'זוהה אירוע בקונים שמצדיק פעולה יזומה.', 'זוהה אירוע בקונים (קונה תקציב מתחת יעד אזור) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'קונים: קונה תקציב מתחת יעד אזור', 'בחן את ההקשר של קונה תקציב מתחת יעד אזור בהקונה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של קונה תקציב מתחת יעד אזור בהקונה, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בקונים (קונה תקציב מתחת יעד אזור) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־14,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'קונים: קונה תקציב מתחת יעד אזור. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (קונים/קונה תקציב מתחת יעד אזור) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.buyer.buyer_budget_fits_hot_territory', 'buyer', 'agent', 'high_priority', 'קונים: הקונה בכוונה גבוהה — חלון הזדמנות', 'הקונה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הקונה מציג סימני כוונה גבוהים — חלון הזדמנות פעיל.', 'הקונה מציג כעת סימני כוונה ובשלות גבוהים מהממוצע (קונה תקציב מתאים חם טריטוריה). זהו חלון הזדמנות קצר שבו פעולה מהירה ומקצועית עשויה להאיץ החלטה ולקדם הכנסה. מומלץ לתעדף ולפעול עוד היום.', 'קונים: הקונה בכוונה גבוהה — חלון הזדמנות', 'הקונה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הקונה חם — תאם צעד מקדם (פגישה/סיור/הצעה) עוד היום, והצג ערך קונקרטי שמתאים לצורך שזוהה.', 'הקונה בעל פוטנציאל גבוה. ודא תיעדוף וטיפול מיידי; שקול ליווי או הקצאה לסוכן חזק.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־14,000 ₪ בעסקה ממוצעת.', 'חלון הכוונה הגבוהה קצר — עיכוב מקטין משמעותית את סיכויי הסגירה.', 'הקונה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'קונים: קונה תקציב מתאים חם טריטוריה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הקונה מקודם להחלטה תוך מיצוי חלון ההזדמנות.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא קונה תקציב מתאים חם טריטוריה. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (קונים/קונה תקציב מתאים חם טריטוריה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
