  ('lib.seller.seller_requires_manager_escalation', 'seller', 'agent', 'manager_review', 'מוכרים: נדרש מבט ניהולי', 'נדרש מבט ניהולי או אישור לפני המשך.', 'נדרש מבט ניהולי או אישור לפני המשך.', 'המוכר הגיע לרף שמצדיק מעורבות ניהולית (מוכר דורש מנהל הסלמה). פעולות בעלות השפעה גבוהה דורשות אישור או ליווי כדי לאזן בין מהירות לבקרה. מומלץ להביא לבחינת מנהל לפני המשך.', 'מוכרים: נדרש מבט ניהולי', 'רכז את הנתונים הרלוונטיים להמוכר והעבר לאישור/ליווי ניהולי לפני פעולה.', 'רכז את הנתונים הרלוונטיים להמוכר והעבר לאישור/ליווי ניהולי לפני פעולה.', 'המוכר דורש החלטה ניהולית (מוכר דורש מנהל הסלמה). בחן את ההקשר, אשר או הנחה את הצעד הבא.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'החלטה ניהולית בזמן מונעת טעויות יקרות בפעולות רגישות.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', 'מוכרים: מוכר דורש מנהל הסלמה. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'ההחלטה הניהולית מתקבלת והפעולה ממשיכה בבקרה.', null, null, null, 'אוטומציה (מוכרים/מוכר דורש מנהל הסלמה) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.seller.seller_should_be_marked_priority', 'seller', 'agent', 'high_priority', 'מוכרים: מוכר סומן עדיפות', 'זוהה אירוע במוכרים שמצדיק פעולה יזומה.', 'זוהה אירוע במוכרים שמצדיק פעולה יזומה.', 'זוהה אירוע במוכרים (מוכר סומן עדיפות) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'מוכרים: מוכר סומן עדיפות', 'בחן את ההקשר של מוכר סומן עדיפות בהמוכר, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של מוכר סומן עדיפות בהמוכר, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע במוכרים (מוכר סומן עדיפות) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־16,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'מוכרים: מוכר סומן עדיפות. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (מוכרים/מוכר סומן עדיפות) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_created', 'property', 'agent', 'quick_win', 'נכסים: הנכס חדש נכנס למערכת', 'הנכס נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הנכס נכנס למערכת וממתין לטיפול ראשוני מסודר.', 'הנכס נוצר זה עתה במערכת. זהו רגע קריטי לרושם ראשוני: טיפול מהיר ומדויק בשלב זה מגדיל משמעותית את סיכויי ההתקדמות. מומלץ להשלים את פרטי הליבה, לוודא שיוך אחראי ולתאם צעד ראשון.', 'נכסים: הנכס חדש נכנס למערכת', 'הנכס חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'הנכס חדש — צור איתו אינטראקציה ראשונה תוך זמן קצר, ודא שכל פרטי הליבה מלאים, וסכם צעד המשך ברור.', 'נקלט הנכס חדש. ודא שהוקצה אחראי ושטופל בחלון הזמן המיטבי כדי לא לאבד מומנטום.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'טיפול מהיר בשלב הראשוני מכפיל את סיכויי ההמרה לעומת טיפול מאוחר.', 'הנכס מטופל, משויך ומקודם לצעד הבא במסלול.', 'נכסים: נכס נוצר. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'הנכס מטופל, משויך ומקודם לצעד הבא במסלול.', 'שלום, ראינו שזה הזמן הנכון להתקדם יחד בנושא נכס נוצר. נשמח לתאם שיחה קצרה ולהציג את הצעדים הבאים המתאימים בדיוק עבורך. (טיוטה — לאישור הסוכן לפני שליחה)', null, null, 'אוטומציה (נכסים/נכס נוצר) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_published', 'property', 'agent', 'high_priority', 'נכסים: נכס פורסם', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים שמצדיק פעולה יזומה.', 'זוהה אירוע בנכסים (נכס פורסם) שמצדיק פעולה יזומה. טיפול עקבי ובזמן באירועים מסוג זה הוא שמבדיל בין מערכת שיודעת לבין משרד שמבצע. מומלץ לבחון את ההקשר ולפעול בצעד ממוקד.', 'נכסים: נכס פורסם', 'בחן את ההקשר של נכס פורסם בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'בחן את ההקשר של נכס פורסם בהנכס, ופעל בצעד ממוקד אחד שמקדם תוצאה.', 'אירוע בנכסים (נכס פורסם) ממתין לפעולה. ודא בעלות וטיפול בזמן.', 'מימוש מוצלח של אירוע זה מגלם פוטנציאל עמלה משוער של כ־15,000 ₪ בעסקה ממוצעת.', 'עקביות בטיפול היא שמייצרת תוצאות לאורך זמן.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', 'נכסים: נכס פורסם. הזדמנות בעלת סיכויי מימוש טובים. מומלץ לתעדף להאצת הכנסה.', 'האירוע מטופל ומקודם לתוצאה מוחשית.', null, null, null, 'אוטומציה (נכסים/נכס פורסם) הכינה פעולות לאישור אנושי. הזדמנות שזוהה.'),
  ('lib.property.property_draft_incomplete', 'property', 'agent', 'follow_up_required', 'נכסים: פער בטיפול בהנכס', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הנכס מציג פער (נכס טיוטה לא שלם) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'נכסים: פער בטיפול בהנכס', 'השלם את החסר בהנכס (נכס טיוטה לא שלם) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהנכס (נכס טיוטה לא שלם) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהנכס. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', 'נכסים: נכס טיוטה לא שלם. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (נכסים/נכס טיוטה לא שלם) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.property.property_missing_seller', 'property', 'agent', 'follow_up_required', 'נכסים: פער בטיפול בהנכס (וריאנט 2)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הנכס מציג פער (נכס חסר מוכר) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'נכסים: פער בטיפול בהנכס (וריאנט 2)', 'השלם את החסר בהנכס (נכס חסר מוכר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהנכס (נכס חסר מוכר) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהנכס. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', 'נכסים: נכס חסר מוכר. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (נכסים/נכס חסר מוכר) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.'),
  ('lib.property.property_missing_decision_maker', 'property', 'agent', 'follow_up_required', 'נכסים: פער בטיפול בהנכס (וריאנט 3)', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'זוהה פער בטיפול או בנתונים שמעכב התקדמות.', 'הנכס מציג פער (נכס חסר החלטה מקבל החלטות) שמעכב התקדמות אפקטיבית. פערים מסוג זה שוחקים סיכויי המרה ונותרים סמויים אם לא מטופלים. מומלץ להשלים את החסר ולחזור למסלול פעיל.', 'נכסים: פער בטיפול בהנכס (וריאנט 3)', 'השלם את החסר בהנכס (נכס חסר החלטה מקבל החלטות) וחזור לטיפול פעיל עם צעד המשך ברור.', 'השלם את החסר בהנכס (נכס חסר החלטה מקבל החלטות) וחזור לטיפול פעיל עם צעד המשך ברור.', 'קיים פער בהנכס. ודא השלמה מהירה כדי למנוע זליגה של הזדמנות.', 'אם לא יטופל בזמן, קיים סיכון לאובדן פוטנציאל עמלה של כ־15,000 ₪ בעסקה ממוצעת מסוג זה.', 'פער שלא נסגר הופך במהירות להזדמנות שאבדה.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', 'נכסים: נכס חסר החלטה מקבל החלטות. סיכון/פער המצריך טיפול לשימור הכנסה צפויה. מומלץ לתעדף השבוע.', 'הפער נסגר והנכס חוזר למסלול טיפול פעיל.', null, null, null, 'אוטומציה (נכסים/נכס חסר החלטה מקבל החלטות) הכינה פעולות לאישור אנושי. סיכון/פער שזוהה.')
